renderScript:
function(wrap, spec) {
  var rows = spec.rows || [];
  if (!rows.length) {
    wrap.style.cssText = 'padding:16px;color:#888;font-size:13px;';
    wrap.textContent = 'Aardvark: no data — SQL must return root, leaf, period, value columns.';
    return;
  }

  var NS = 'http://www.w3.org/2000/svg';
  var i, j, r, lk, bk, rk, val, br, x, agg, s, lb, c, rt;
  var hasBranch = false;
  for (i = 0; i < rows.length; i++) { if (rows[i].branch != null && rows[i].branch !== '') { hasBranch = true; break; } }

  var pSet = {};
  for (i = 0; i < rows.length; i++) if (rows[i].period) pSet[rows[i].period] = 1;
  var periods = Object.keys(pSet).sort();
  var nP = periods.length;
  if (!nP) { wrap.textContent = 'Aardvark: period column is empty.'; return; }
  var pIdx = {};
  for (i = 0; i < nP; i++) pIdx[periods[i]] = i;

  var leafSer = {}, branchSer = {}, rootSer = {};
  for (i = 0; i < rows.length; i++) {
    r = rows[i];
    var pi = pIdx[r.period];
    if (pi === undefined) continue;
    val = +(r.value || 0);
    br = r.branch || '';
    lk = r.root + '||' + br + '||' + r.leaf;
    bk = r.root + '||' + br;
    rk = r.root;
    if (!leafSer[lk]) { leafSer[lk] = new Array(nP).fill(0); }
    if (!branchSer[bk]) { branchSer[bk] = new Array(nP).fill(0); }
    if (!rootSer[rk]) { rootSer[rk] = new Array(nP).fill(0); }
    leafSer[lk][pi] += val;
    branchSer[bk][pi] += val;
    rootSer[rk][pi] += val;
  }

  var seen = {}, leafList = [];
  for (i = 0; i < rows.length; i++) {
    r = rows[i];
    lk = r.root + '||' + (r.branch || '') + '||' + r.leaf;
    if (!seen[lk]) { seen[lk] = 1; leafList.push({ root: r.root, branch: r.branch || null, leaf: r.leaf, key: lk }); }
  }
  var nL = leafList.length;

  var PAD_L = 12, PAD_R = 20, PAD_T = 44, PAD_B = 32;
  var ROW_H = 30;
  var ROOT_W = 82, BRANCH_W = hasBranch ? 88 : 0, LEAF_LW = 108;
  var LABEL_W = ROOT_W + BRANCH_W + LEAF_LW;
  var W = Math.max(560, (wrap.clientWidth || wrap.offsetWidth || 800) - 32);
  var SERIES_X0 = PAD_L + LABEL_W;
  var SERIES_W = W - SERIES_X0 - PAD_R;
  var H = PAD_T + nL * ROW_H + PAD_B;

  var COLORS = ['#534AB7','#2E9CDB','#E8833A','#4BC1A8','#E85858','#9B59B6','#27AE60','#F39C12'];
  var rootOrder = [], rootColorMap = {};
  for (i = 0; i < leafList.length; i++) {
    rt = leafList[i].root;
    if (!rootColorMap[rt]) { rootColorMap[rt] = COLORS[rootOrder.length % COLORS.length]; rootOrder.push(rt); }
  }

  var maxAll = 1;
  var lkeys = Object.keys(leafSer);
  for (i = 0; i < lkeys.length; i++) {
    s = leafSer[lkeys[i]];
    for (j = 0; j < s.length; j++) if (s[j] > maxAll) maxAll = s[j];
  }

  var el = function(tag, attrs, par) {
    var e = document.createElementNS(NS, tag);
    if (attrs) for (var k in attrs) e.setAttribute(k, attrs[k]);
    if (par) par.appendChild(e);
    return e;
  };
  var tx = function(tag, attrs, text, par) {
    var e = el(tag, attrs, par); e.textContent = text; return e;
  };
  var clip = function(str, n) { str = String(str); return str.length > n ? str.slice(0, n - 1) + '\u2026' : str; };

  wrap.innerHTML = '';
  var svgW = SERIES_X0 + SERIES_W + PAD_R;
  var outer = document.createElement('div');
  outer.style.cssText = 'overflow-x:auto;';
  wrap.appendChild(outer);
  var svg = el('svg', { width: svgW, height: H, style: 'display:block;font-family:system-ui,sans-serif;' }, outer);
  el('rect', { x: 0, y: 0, width: svgW, height: H, fill: 'var(--bg,#fff)' }, svg);

  if (spec.title) {
    tx('text', { x: svgW / 2, y: 20, 'text-anchor': 'middle', 'font-size': '13', 'font-weight': '500', fill: 'var(--text,#222)' }, spec.title, svg);
  }

  var xOf = function(pi) { return SERIES_X0 + (pi + 0.5) / nP * SERIES_W; };
  var step = Math.max(1, Math.ceil(nP / 10));
  for (i = 0; i < nP; i++) {
    if (i % step !== 0) continue;
    x = xOf(i);
    el('line', { x1: x, y1: PAD_T - 5, x2: x, y2: H - PAD_B, stroke: 'var(--border,#eee)', 'stroke-width': '1' }, svg);
    var plbl = periods[i]; if (plbl.length > 7) plbl = plbl.slice(2);
    tx('text', { x: x, y: PAD_T - 7, 'text-anchor': 'middle', 'font-size': '9', fill: 'var(--text3,#aaa)' }, plbl, svg);
  }
  el('line', { x1: SERIES_X0, y1: PAD_T, x2: SERIES_X0 + SERIES_W, y2: PAD_T, stroke: 'var(--border2,#ccc)', 'stroke-width': '1' }, svg);
  el('line', { x1: SERIES_X0, y1: PAD_T - 20, x2: SERIES_X0, y2: H - PAD_B, stroke: 'var(--border2,#ccc)', 'stroke-width': '1' }, svg);

  var makePath = function(series, x0, y0, w, h, useLocal) {
    var mx = 1;
    if (useLocal) { for (var ii = 0; ii < series.length; ii++) if (series[ii] > mx) mx = series[ii]; }
    else { mx = maxAll; }
    var pts = [];
    for (var ii = 0; ii < series.length; ii++) {
      pts.push(x0 + (ii + 0.5) / series.length * w + ',' + (y0 + h - series[ii] / mx * h * 0.9));
    }
    return 'M ' + pts.join(' L ');
  };
  var makeArea = function(series, x0, y0, w, h) {
    var mx = 1;
    for (var ii = 0; ii < series.length; ii++) if (series[ii] > mx) mx = series[ii];
    var top = [];
    for (var ii = 0; ii < series.length; ii++) {
      top.push(x0 + (ii + 0.5) / series.length * w + ',' + (y0 + h - series[ii] / mx * h * 0.88));
    }
    if (!top.length) return '';
    return 'M ' + x0 + ',' + (y0 + h) + ' L ' + top.join(' L ') + ' L ' + (x0 + w) + ',' + (y0 + h) + ' Z';
  };

  var prevRoot = null, prevBranch = null, rootSI = 0, branchSI = 0;

  var flushRoot = function(endI, root) {
    if (!root) return;
    var y0 = PAD_T + rootSI * ROW_H;
    var bH = (endI - rootSI) * ROW_H;
    if (bH <= 0) return;
    var col = rootColorMap[root];
    el('rect', { x: PAD_L, y: y0, width: ROOT_W - 2, height: bH, rx: '3', fill: col, opacity: '0.08' }, svg);
    el('line', { x1: PAD_L, y1: y0, x2: svgW - PAD_R, y2: y0, stroke: col, 'stroke-width': '1.5', opacity: '0.35' }, svg);
    agg = rootSer[root];
    if (agg) {
      var aD = makeArea(agg, SERIES_X0, y0, SERIES_W, bH);
      if (aD) el('path', { d: aD, fill: col, opacity: '0.07' }, svg);
      var aL = makePath(agg, SERIES_X0, y0, SERIES_W, bH, true);
      el('path', { d: aL, fill: 'none', stroke: col, 'stroke-width': '1.5', opacity: '0.25', 'stroke-dasharray': '5,3' }, svg);
    }
    tx('text', { x: PAD_L + 5, y: y0 + bH / 2 + 4, 'font-size': '11', 'font-weight': '700', fill: col }, clip(root, 10), svg);
  };

  var flushBranch = function(endI, root, branch) {
    if (!hasBranch || !branch) return;
    var y0 = PAD_T + branchSI * ROW_H;
    var bH = (endI - branchSI) * ROW_H;
    if (bH <= 0) return;
    var col = rootColorMap[root];
    if (branchSI > rootSI) {
      el('line', { x1: PAD_L + ROOT_W, y1: y0, x2: svgW - PAD_R, y2: y0, stroke: 'var(--border,#e0e0e0)', 'stroke-width': '0.5', 'stroke-dasharray': '4,3' }, svg);
    }
    tx('text', { x: PAD_L + ROOT_W + 4, y: y0 + bH / 2 + 4, 'font-size': '10', 'font-weight': '600', fill: col, opacity: '0.8' }, clip(branch, 12), svg);
  };

  for (i = 0; i < nL; i++) {
    var row = leafList[i];
    var y = PAD_T + i * ROW_H;
    var col = rootColorMap[row.root];
    var rootChanged = row.root !== prevRoot;
    var branchChanged = rootChanged || (row.branch !== prevBranch);

    if (rootChanged) {
      flushRoot(i, prevRoot);
      flushBranch(i, prevRoot, prevBranch);
      rootSI = i; branchSI = i;
    } else if (branchChanged) {
      flushBranch(i, row.root, prevBranch);
      branchSI = i;
    }
    prevRoot = row.root; prevBranch = row.branch;

    if (i % 2 === 0) el('rect', { x: SERIES_X0, y: y, width: SERIES_W, height: ROW_H, fill: 'var(--bg2,#f7f6f2)', opacity: '0.45' }, svg);

    el('circle', { cx: SERIES_X0 - 5, cy: y + ROW_H / 2, r: '3', fill: col, opacity: '0.7' }, svg);

    tx('text', { x: SERIES_X0 - 12, y: y + ROW_H / 2 + 4, 'text-anchor': 'end', 'font-size': '10', fill: 'var(--text2,#555)' }, clip(row.leaf, 15), svg);

    s = leafSer[row.key];
    if (s) {
      var lp = makePath(s, SERIES_X0, y + 3, SERIES_W, ROW_H - 6, false);
      el('path', { d: lp, fill: 'none', stroke: col, 'stroke-width': '1.3', opacity: '0.85' }, svg);
    }

    el('line', { x1: SERIES_X0, y1: y + ROW_H, x2: SERIES_X0 + SERIES_W, y2: y + ROW_H, stroke: 'var(--border,#eee)', 'stroke-width': '0.5' }, svg);

    if (s) {
      var tipRect = el('rect', { x: SERIES_X0, y: y, width: SERIES_W, height: ROW_H, fill: 'transparent', cursor: 'crosshair' }, svg);
      var ttNode = document.createElementNS(NS, 'title');
      var peakV = 0, peakP = '';
      for (j = 0; j < s.length; j++) { if (s[j] > peakV) { peakV = s[j]; peakP = periods[j]; } }
      ttNode.textContent = row.leaf + '\nPeak: ' + peakP + ' = ' + Math.round(peakV).toLocaleString();
      tipRect.appendChild(ttNode);
    }
  }

  flushRoot(nL, prevRoot);
  flushBranch(nL, prevRoot, prevBranch);

  el('line', { x1: PAD_L, y1: PAD_T + nL * ROW_H, x2: svgW - PAD_R, y2: PAD_T + nL * ROW_H, stroke: 'var(--border2,#ccc)', 'stroke-width': '1' }, svg);

  var lx = SERIES_X0, ly = H - 12;
  for (i = 0; i < rootOrder.length && i < 7; i++) {
    rt = rootOrder[i]; c = rootColorMap[rt];
    el('rect', { x: lx, y: ly - 7, width: 8, height: 8, rx: '2', fill: c }, svg);
    lb = clip(rt, 16);
    tx('text', { x: lx + 11, y: ly, 'font-size': '10', fill: 'var(--text2,#555)' }, lb, svg);
    lx += Math.min(lb.length * 6.5, 110) + 22;
    if (lx > svgW - 80) break;
  }
}
